using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string Text { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 20)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;

    public int OriginalLength { get; set; }

    public int SummaryLength { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizationService
{
    // Common English stop words excluded from scoring
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","could",
        "should","may","might","shall","can","need","dare","ought","used",
        "to","of","in","for","on","with","at","by","from","as","into",
        "through","during","before","after","above","below","between",
        "out","off","over","under","again","further","then","once","that",
        "this","these","those","it","its","i","me","my","we","our","you",
        "your","he","him","his","she","her","they","them","their","what",
        "which","who","whom","where","when","why","how","not","no","nor",
        "so","if","about","up","than","too","very","just","also"
    };

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"[^\w\s]")]
    private static partial Regex PunctuationStripper();

    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scored = ScoreSentences(sentences, wordFrequencies);

        // Pick the top-scored sentences, preserving original order
        var topIndices = scored
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .Select(s => s.Index)
            .OrderBy(i => i)
            .ToList();

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    private static List<string> SplitSentences(string text)
    {
        return SentenceSplitter()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (!StopWords.Contains(word))
                    freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }

        return freq;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences,
        Dictionary<string, int> wordFrequencies)
    {
        var maxFreq = wordFrequencies.Values.DefaultIfEmpty(1).Max();
        var scored = new List<(int Index, double Score)>();

        for (int i = 0; i < sentences.Count; i++)
        {
            double score = Tokenize(sentences[i])
                .Where(w => wordFrequencies.ContainsKey(w))
                .Sum(w => (double)wordFrequencies[w] / maxFreq);

            scored.Add((i, score));
        }

        return scored;
    }

    private static IEnumerable<string> Tokenize(string text)
    {
        var cleaned = PunctuationStripper().Replace(text, "");
        return cleaned.Split(' ', StringSplitOptions.RemoveEmptyEntries);
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _service;

    public SummarizeController(DocumentSummarizationService service)
    {
        _service = service;
    }

    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _service.Summarize(request.Text, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.Text.Length,
            SummaryLength = summary.Length
        });
    }
}

